import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Schedule {
  time: string;
  setTemp: number;
}

interface ThermostatData {
  currentTemperature: number;
  targetTemperature: number;
  schedule: Schedule[];
}

export default function Widget() {
  const thermostatData = response.data as ThermostatData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Current Temperature
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              {thermostatData.currentTemperature}°F
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8', mt: 0.5 }}>
              Target: {thermostatData.targetTemperature}°F
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: thermostatData.schedule.map(s => s.setTemp),
                  color: '#FFC107',
                  label: 'Scheduled Temperature',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: thermostatData.schedule.map(s => s.time),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'temperature' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="temperature"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {thermostatData.schedule.slice(0, 5).map((schedule, index) => (
              <Chip
                key={index}
                label={`${schedule.time}: ${schedule.setTemp}°F`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#374151', color: '#F8FAFC' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
